import { createRouter, createWebHistory, createWebHashHistory, RouteRecordRaw } from 'vue-router'
import HelloView from '../views/sample/HelloView.vue'

const routes: Array<RouteRecordRaw> = [
  {
    path: '/',
    name: 'home',
    component: HelloView
  },
  {
    path: '/login',
    name: 'login',
    component: () => import(/* webpackChunkName: "login" */ '../views/LoginView.vue') // webpackChunkName 특별한 주석으로 처리
  },
  {
    path: '/sample/about',
    name: 'about',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () => import(/* webpackChunkName: "about" */ '../views/sample/AboutView.vue')
  },
  {
    path: '/sample',
    name: 'thisissample',
    component: () => import(/* webpackChunkName: "sample" */ '../views/sample/SampleView.vue')
  }
]

const router = createRouter({
  history: createWebHistory(), //createWebHashHistory(),
  routes
})

export default router
